import type {
    Styleframe,
    Recipe,
    VariantDeclarationsBlock,
} from "@styleframe/core";
import { defu } from "defu";

export type RecipeConfig<
    Variants extends Record<
        string,
        Record<string, VariantDeclarationsBlock>
    > = Record<string, Record<string, VariantDeclarationsBlock>>,
> = {
    base?: VariantDeclarationsBlock;
    variants?: Variants;
    defaultVariants?: {
        [K in keyof Variants]?: keyof Variants[K] & string;
    };
    compoundVariants?: Array<{
        match: {
            [K in keyof Variants]?: keyof Variants[K] & string;
        };
        css?: VariantDeclarationsBlock;
        className?: string;
    }>;
};

export type DeepPartial<T> = {
    [P in keyof T]?: T[P] extends object ? DeepPartial<T[P]> : T[P];
};

export type FilterConfig<
    Variants extends Record<string, Record<string, VariantDeclarationsBlock>>,
> = {
    [K in keyof Variants]?: Array<keyof Variants[K] & string>;
};

export type ApplyFilter<
    V extends Record<string, Record<string, VariantDeclarationsBlock>>,
    F,
> = {
    [K in keyof V]: K extends keyof F
        ? F[K] extends (infer U)[]
            ? Pick<V[K], Extract<U, keyof V[K]>>
            : V[K]
        : V[K];
};

function applyFilter(
    config: RecipeConfig,
    filter: Record<string, string[] | undefined>,
): RecipeConfig {
    const result = { ...config };

    if (result.variants) {
        const filteredVariants = { ...result.variants };
        for (const axis of Object.keys(filter)) {
            const allowedValues = filter[axis];
            if (!allowedValues || !(axis in filteredVariants)) continue;

            const allowedSet = new Set(allowedValues);
            const original = filteredVariants[axis];
            if (!original) continue;

            const filtered: Record<string, VariantDeclarationsBlock> = {};
            for (const [key, value] of Object.entries(original)) {
                if (allowedSet.has(key)) {
                    filtered[key] = value;
                }
            }
            filteredVariants[axis] = filtered;
        }
        result.variants = filteredVariants;
    }

    if (result.compoundVariants) {
        result.compoundVariants = result.compoundVariants.filter((compound) => {
            for (const [axis, matchValue] of Object.entries(compound.match)) {
                const allowedValues = filter[axis];
                if (allowedValues) {
                    const allowedSet = new Set(allowedValues);
                    if (!allowedSet.has(matchValue as string)) {
                        return false;
                    }
                }
            }
            return true;
        });
    }

    if (result.defaultVariants) {
        const adjustedDefaults = { ...result.defaultVariants };
        for (const axis of Object.keys(filter)) {
            const allowedValues = filter[axis];
            if (!allowedValues || !(axis in adjustedDefaults)) continue;

            const allowedSet = new Set(allowedValues);
            const currentDefault = (adjustedDefaults as Record<string, string>)[axis];
            if (currentDefault && !allowedSet.has(currentDefault)) {
                delete (adjustedDefaults as Record<string, string>)[axis];
            }
        }
        result.defaultVariants = adjustedDefaults;
    }

    return result;
}

export function createUseRecipe<
    Name extends string,
    const Config extends RecipeConfig,
>(name: Name, defaults: Config, setup?: (s: Styleframe) => void) {
    type Variants = NonNullable<Config["variants"]>;

    return function useRecipe<F extends FilterConfig<Variants> = {}>(
        s: Styleframe,
        options?: DeepPartial<RecipeConfig<Variants>> & { filter?: F },
    ): Recipe<Name, ApplyFilter<Variants, F>> {
        if (setup) {
            setup(s);
        }

        const { filter, ...configOverrides } = options ?? {};
        const merged = defu(configOverrides, defaults) as RecipeConfig;
        const filtered = filter ? applyFilter(merged, filter) : merged;
        const recipe = s.recipe({
            name,
            ...filtered,
        }) as Recipe<Name, ApplyFilter<Variants, F>>;

        return recipe;
    };
}

import {
    isKeyReferenceValue,
    type DeclarationsCallbackContext,
    type TokenValue,
    type Variable,
} from "@styleframe/core";
import type { CamelCase } from "scule";
import { camelCase } from "scule";
import type { ExportKeys } from "../types";

export function createUseVariable<
    PropertyName extends string,
    PropertyType = TokenValue,
    Delimiter extends string = ".",
    Defaults extends Record<string, PropertyType> = Record<string, PropertyType>,
    MergeDefaults extends boolean = false,
>(
    propertyName: PropertyName,
    {
        defaults,
        mergeDefaults = false as MergeDefaults,
        transform = (value) => value as TokenValue,
        delimiter = "." as Delimiter,
    }: {
        defaults?: Defaults;
        mergeDefaults?: MergeDefaults;
        transform?: (value: PropertyType) => TokenValue;
        delimiter?: Delimiter;
    } = {},
) {
    type WithDefaults<T> = MergeDefaults extends true ? Defaults & T : T;

    return function useVariable<
        Context extends DeclarationsCallbackContext = DeclarationsCallbackContext,
        T extends Record<string, PropertyType> = Defaults,
    >(
        s: Context,
        tokens?: T,
        { default: isDefault = true }: { default?: boolean } = {},
    ): ExportKeys<PropertyName, WithDefaults<T>, Delimiter> {
        const result: Record<string, Variable<string>> = {};

        const resolvedTokens = mergeDefaults
            ? ({ ...defaults, ...tokens } as T)
            : ((tokens ?? defaults ?? {}) as T);
        const pairs = Object.entries(resolvedTokens);

        pairs.sort(([_aKey, aValue], [_bKey, bValue]) => {
            if (isKeyReferenceValue(aValue)) return 1;
            if (isKeyReferenceValue(bValue)) return -1;
            return 0;
        });

        const createVariableName = (key: string) =>
            `${propertyName}${key === "default" ? "" : `${delimiter}${key}`}` as const;

        for (const [key, value] of pairs) {
            const variableName = createVariableName(key);
            const exportName: CamelCase<typeof variableName> =
                camelCase(variableName);

            const variableValue = isKeyReferenceValue(value)
                ? (value as unknown as TokenValue)
                : transform(value);

            result[exportName] = s.variable(variableName, variableValue, {
                default: isDefault,
            });
        }

        return result as ExportKeys<PropertyName, WithDefaults<T>, Delimiter>;
    };
}

import type {
    ModifierFactory,
    Styleframe,
