                },
                {
                    match: { color: "primary", variant: "outline" },
                    css: { borderColor: "blue" },
                },
                {
                    match: { color: "error", variant: "solid" },
                    css: { background: "red" },
                },
                {
                    match: { color: "error", variant: "outline" },
                    css: { borderColor: "red" },
