import type { Utility } from "@styleframe/core";
import { isUtility, styleframe } from "@styleframe/core";
import { consumeCSS } from "@styleframe/transpiler";
import { createUseSpacingUtility } from "./createUseSpacingUtility";

describe("createUseSpacingUtility", () => {
    it("should return a function", () => {
        const useMargin = createUseSpacingUtility("margin", ({ value }) => ({
            margin: value,
        }));
        expect(typeof useMargin).toBe("function");
    });

    it("should create a composable with multiplier support", () => {
        const useMargin = createUseSpacingUtility("margin", ({ value }) => ({
            margin: value,
        }));
        const s = styleframe();
        s.variable("spacing", "1rem");

        const createMargin = useMargin(s);
        createMargin(["@1.5", "@2", "@-1"]);

        const utilities = s.root.children.filter(
            (u): u is Utility => isUtility(u) && u.name === "margin",
        );
        expect(utilities).toHaveLength(3);
    });

    it("should generate correct calc CSS output for decimal multipliers", () => {
        const useMargin = createUseSpacingUtility("margin", ({ value }) => ({
            margin: value,
        }));
        const s = styleframe();
        s.variable("spacing", "1rem");

        const createMargin = useMargin(s);
        createMargin(["@1.5"]);

        const css = consumeCSS(s.root, s.options);
        expect(css).toContain("._margin\\:1\\.5 {");
        expect(css).toContain("margin: calc(var(--spacing, 1rem) * 1.5);");
    });

    it("should generate correct calc CSS output for integer multipliers", () => {
        const useMargin = createUseSpacingUtility("margin", ({ value }) => ({
            margin: value,
        }));
        const s = styleframe();
        s.variable("spacing", "1rem");

        const createMargin = useMargin(s);
        createMargin(["@2"]);

        const css = consumeCSS(s.root, s.options);
        expect(css).toContain("._margin\\:2 {");
        expect(css).toContain("margin: calc(var(--spacing, 1rem) * 2);");
    });

    it("should generate correct calc CSS output for negative multipliers", () => {
        const useMargin = createUseSpacingUtility("margin", ({ value }) => ({
            margin: value,
        }));
        const s = styleframe();
        s.variable("spacing", "1rem");

        const createMargin = useMargin(s);
        createMargin(["@-1"]);

        const css = consumeCSS(s.root, s.options);
        expect(css).toContain("._margin\\:-1 {");
        expect(css).toContain("margin: calc(var(--spacing, 1rem) * -1);");
    });

    it("should work with named values alongside multipliers", () => {
        const useMargin = createUseSpacingUtility("margin", ({ value }) => ({
            margin: value,
        }));
        const s = styleframe();
        s.variable("spacing", "1rem");

        useMargin(s, { sm: "0.5rem", md: "1rem" });
        const createMargin = s.root.utilities[0]?.create;
        createMargin?.(["@1.5", "@2"]);

        const css = consumeCSS(s.root, s.options);
        expect(css).toContain("._margin\\:sm {");
        expect(css).toContain("margin: 0.5rem;");
        expect(css).toContain("._margin\\:1\\.5 {");
        expect(css).toContain("margin: calc(var(--spacing, 1rem) * 1.5);");
    });

    it("should allow custom base variable", () => {
        const useGap = createUseSpacingUtility(
            "gap",
            ({ value }) => ({ gap: value }),
            { baseVariable: "gap-base" },
        );
        const s = styleframe();
        s.variable("gap-base", "0.5rem");

        const createGap = useGap(s);
        createGap(["@2"]);

        const css = consumeCSS(s.root, s.options);
        expect(css).toContain("gap: calc(var(--gap-base, 1rem) * 2);");
    });

    it("should handle Variable object as base variable without fallback", () => {
        const s = styleframe();
        const spacingVar = s.variable("my-spacing", "0.5rem");

        const useMargin = createUseSpacingUtility(
            "margin",
            ({ value }) => ({ margin: value }),
            { baseVariable: spacingVar },
        );

        const createMargin = useMargin(s);
        createMargin(["@1.5"]);

        const css = consumeCSS(s.root, s.options);
        expect(css).toContain("margin: calc(var(--my-spacing) * 1.5);");
        expect(css).not.toContain("margin: calc(var(--my-spacing, ");
    });

    it("should use fallback value when base variable is not defined", () => {
        const useMargin = createUseSpacingUtility(
            "margin",
            ({ value }) => ({ margin: value }),
            { fallback: "0.5rem" },
        );
        const s = styleframe();

        const createMargin = useMargin(s);
        createMargin(["@2"]);

        const css = consumeCSS(s.root, s.options);
        expect(css).toContain("margin: calc(var(--spacing, 0.5rem) * 2);");
    });

    it("should use default fallback of 1rem", () => {
        const useMargin = createUseSpacingUtility("margin", ({ value }) => ({
            margin: value,
        }));
        const s = styleframe();

        const createMargin = useMargin(s);
        createMargin(["@2"]);

        const css = consumeCSS(s.root, s.options);
        expect(css).toContain("margin: calc(var(--spacing, 1rem) * 2);");
    });

    it("should fall back to default behavior for @ references", () => {
        const useMargin = createUseSpacingUtility("margin", ({ value }) => ({
            margin: value,
        }));
        const s = styleframe();
        s.variable("spacing.sm", "0.5rem");

        const createMargin = useMargin(s);
        createMargin(["@spacing.sm"]);

        const css = consumeCSS(s.root, s.options);
        expect(css).toContain("._margin\\:spacing\\.sm {");
        expect(css).toContain("margin: var(--spacing--sm);");
    });

    it("should fall back to default behavior for arbitrary values", () => {
        const useMargin = createUseSpacingUtility("margin", ({ value }) => ({
            margin: value,
        }));
        const s = styleframe();

        const createMargin = useMargin(s);
        createMargin(["auto"]);

        const css = consumeCSS(s.root, s.options);
        expect(css).toContain("._margin\\:\\[auto\\] {");
        expect(css).toContain("margin: auto;");
    });

    it("should support defaults option", () => {
        const useMargin = createUseSpacingUtility(
            "margin",
            ({ value }) => ({ margin: value }),
            { defaults: { sm: "0.5rem", md: "1rem" } },
        );
        const s = styleframe();

        useMargin(s);

        const css = consumeCSS(s.root, s.options);
        expect(css).toContain("._margin\\:sm {");
        expect(css).toContain("._margin\\:md {");
    });

    it("should support mergeDefaults option", () => {
        const useMargin = createUseSpacingUtility(
            "margin",
            ({ value }) => ({ margin: value }),
            { defaults: { sm: "0.5rem" }, mergeDefaults: true },
        );
        const s = styleframe();

        useMargin(s, { lg: "1.5rem" });

        const css = consumeCSS(s.root, s.options);
        expect(css).toContain("._margin\\:sm {");
        expect(css).toContain("._margin\\:lg {");
    });

    it("should work with modifiers", () => {
        const useMargin = createUseSpacingUtility("margin", ({ value }) => ({
            margin: value,
        }));
        const s = styleframe();
        s.variable("spacing", "1rem");

        const hover = s.modifier("hover", ({ declarations }) => ({
            "&:hover": declarations,
        }));

        const createMargin = useMargin(s, { sm: "0.5rem" }, [hover]);
        createMargin(["@1.5"], [hover]);

        const css = consumeCSS(s.root, s.options);
        expect(css).toContain("._margin\\:sm {");
        expect(css).toContain("._margin\\:1\\.5 {");
        expect(css).toContain("._hover\\:margin\\:sm {");
        expect(css).toContain("._hover\\:margin\\:1\\.5 {");
    });

    it("should return the utility creator function", () => {
        const useMargin = createUseSpacingUtility("margin", ({ value }) => ({
            margin: value,
        }));
        const s = styleframe();

        const createMargin = useMargin(s);

        expect(typeof createMargin).toBe("function");
    });

    it("should handle empty values object", () => {
        const useMargin = createUseSpacingUtility("margin", ({ value }) => ({
            margin: value,
        }));
        const s = styleframe();

        useMargin(s, {});

        expect(s.root.children).toHaveLength(0);
    });

    describe("utilityOptions.name override", () => {
        it("should override the utility name", () => {
            const useMargin = createUseSpacingUtility("margin", ({ value }) => ({
                margin: value,
            }));
            const s = styleframe();
            s.variable("spacing", "1rem");

            useMargin(s, { sm: "0.5rem" }, undefined, { name: "m" });

            const css = consumeCSS(s.root, s.options);
            expect(css).toContain("._m\\:sm {");
            expect(css).not.toContain("._margin");
        });

        it("should override the utility name for multiplier values", () => {
            const useMargin = createUseSpacingUtility("margin", ({ value }) => ({
                margin: value,
            }));
            const s = styleframe();
            s.variable("spacing", "1rem");

            const createMargin = useMargin(s, undefined, undefined, { name: "m" });
            createMargin(["@1.5"]);

            const css = consumeCSS(s.root, s.options);
            expect(css).toContain("._m\\:1\\.5 {");
            expect(css).not.toContain("._margin");
        });

        it("should use default name when no override provided", () => {
            const useMargin = createUseSpacingUtility("margin", ({ value }) => ({
                margin: value,
            }));
            const s = styleframe();

            useMargin(s, { sm: "0.5rem" });

            expect(s.root.utilities[0]?.name).toBe("margin");
        });
    });
});

import type {
    DeclarationsCallbackContext,
    TokenValue,
    Variable,
} from "@styleframe/core";
import type { ExportKeys } from "../types";
import { createUseVariable } from "./createUseVariable";

export function createUseDerivedVariable<
    PropertyType = TokenValue,
    Delimiter extends string = ".",
    Defaults extends Record<string, PropertyType> = Record<string, PropertyType>,
>({
    defaults,
    transform,
    delimiter,
}: {
    defaults?: Defaults;
    transform: (
        value: PropertyType,
        context: { s: DeclarationsCallbackContext; parent: Variable },
    ) => TokenValue;
    delimiter?: Delimiter;
}) {
    return function useDerivedVariable<
        Context extends DeclarationsCallbackContext,
        Name extends string,
        T extends Record<string | number, PropertyType> = Defaults,
    >(
        s: Context,
        parent: Variable<Name>,
        tokens: T,
        { default: isDefault = true }: { default?: boolean } = {},
    ): ExportKeys<Name, T, Delimiter> {
        return createUseVariable(parent.name, {
            defaults: defaults as Record<string, TokenValue> | undefined,
            transform: (value) => transform(value as PropertyType, { s, parent }),
            delimiter,
        })(s, tokens as Record<string, TokenValue>, {
            default: isDefault,
        }) as ExportKeys<Name, T, Delimiter>;
    };
}

import type { WithThemes } from "../types";

export function mergeElementOptions<T extends object>(
    defaults: WithThemes<T>,
    overrides: WithThemes<T>,
): WithThemes<T> {
    const { themes: defaultThemes, ...defaultConfig } = defaults;
    const { themes: userThemes, ...userConfig } = overrides;

    const mergedConfig = { ...defaultConfig, ...userConfig } as T;

    let mergedThemes: Record<string, T> | undefined;
    if (defaultThemes || userThemes) {
        mergedThemes = {};
        const themeNames = new Set([
            ...Object.keys(defaultThemes ?? {}),
            ...Object.keys(userThemes ?? {}),
        ]);
        for (const name of themeNames) {
            mergedThemes[name] = {
                ...defaultThemes?.[name],
                ...userThemes?.[name],
            } as T;
        }
    }

    return { ...mergedConfig, themes: mergedThemes } as WithThemes<T>;
}

import type { DeclarationsCallbackContext, Styleframe } from "@styleframe/core";

export function registerElementThemes<T>(
    s: Styleframe,
    themes: Record<string, T> | undefined,
    applyDesignTokens: (ctx: DeclarationsCallbackContext, config: T) => void,
): void {
    if (!themes) return;
    for (const [themeName, overrides] of Object.entries(themes)) {
        s.theme(themeName, (ctx) => {
            applyDesignTokens(ctx, overrides);
        });
    }
}

import { describe, expect, it } from "vitest";
import {
    computeLightnessColor,
    computeRelativeColor,
    findMaxChroma,
    formatOklch,
    parseOklch,
} from "./oklchGamut";

describe("oklchGamut", () => {
    describe("parseOklch", () => {
        it("should parse hex color strings", () => {
            const result = parseOklch("#007bff");
            expect(result).toBeDefined();
            expect(result!.l).toBeCloseTo(0.57, 1);
            expect(result!.c).toBeGreaterThan(0);
            expect(result!.h).toBeGreaterThan(0);
            expect(result!.alpha).toBe(1);
        });

        it("should parse oklch CSS strings", () => {
            const result = parseOklch("oklch(0.5 0.19 258.8 / 1)");
            expect(result).toBeDefined();
            expect(result!.l).toBeCloseTo(0.5, 2);
            expect(result!.c).toBeCloseTo(0.19, 2);
            expect(result!.h).toBeCloseTo(258.8, 1);
            expect(result!.alpha).toBe(1);
        });

        it("should parse oklch without alpha", () => {
            const result = parseOklch("oklch(0.5 0.19 258.8)");
            expect(result).toBeDefined();
            expect(result!.alpha).toBe(1);
        });

        it("should handle black (achromatic, no hue)", () => {
            const result = parseOklch("#000000");
            expect(result).toBeDefined();
            expect(result!.l).toBeCloseTo(0, 2);
            expect(result!.c).toBeCloseTo(0, 3);
        });

        it("should handle white (achromatic, no hue)", () => {
            const result = parseOklch("#ffffff");
            expect(result).toBeDefined();
            expect(result!.l).toBeCloseTo(1, 2);
            expect(result!.c).toBeCloseTo(0, 3);
        });

        it("should return undefined for invalid strings", () => {
            expect(parseOklch("not-a-color")).toBeUndefined();
        });
    });

    describe("findMaxChroma", () => {
        it("should return near-zero for L=0 (black)", () => {
            expect(findMaxChroma(0, 240)).toBeLessThan(0.05);
        });

        it("should return near-zero for L=1 (white)", () => {
            expect(findMaxChroma(1, 240)).toBeLessThan(0.05);
        });

        it("should return positive chroma for mid-range lightness", () => {
            const maxC = findMaxChroma(0.5, 240);
            expect(maxC).toBeGreaterThan(0.05);
        });

        it("should vary by hue", () => {
            const maxBlue = findMaxChroma(0.5, 260);
            const maxYellow = findMaxChroma(0.5, 100);
            expect(maxBlue).not.toBeCloseTo(maxYellow, 2);
        });
    });

    describe("computeLightnessColor", () => {
        it("should produce a valid oklch string", () => {
            const result = computeLightnessColor(0.55, 0.15, 240, 1, 0.93);
            expect(result).toMatch(/^oklch\(.+ .+ .+ \/ .+\)$/);
        });

        it("should keep achromatic colors achromatic", () => {
            const result = computeLightnessColor(0.5, 0, 0, 1, 0.93);
            expect(result).toContain(" 0 ");
        });

        it("should reduce chroma at extreme lightness levels", () => {
            const baseL = 0.55;
            const baseC = 0.15;
            const baseH = 240;

            const lightResult = computeLightnessColor(baseL, baseC, baseH, 1, 0.97);
            const midResult = computeLightnessColor(baseL, baseC, baseH, 1, 0.55);

            const lightC = Number.parseFloat(lightResult.split(" ")[1] ?? "0");
            const midC = Number.parseFloat(midResult.split(" ")[1] ?? "0");

            expect(lightC).toBeLessThan(midC);
        });

        it("should preserve alpha", () => {
            const result = computeLightnessColor(0.55, 0.15, 240, 0.5, 0.93);
            expect(result).toContain("/ 0.5");
        });

        it("should work with known color #007bff at various lightness targets", () => {
            const parsed = parseOklch("#007bff")!;

            const light = computeLightnessColor(
                parsed.l,
                parsed.c,
                parsed.h,
                parsed.alpha,
                0.93,
            );
            expect(light).toMatch(/^oklch\(/);

            const dark = computeLightnessColor(
                parsed.l,
                parsed.c,
                parsed.h,
                parsed.alpha,
                0.17,
            );
            expect(dark).toMatch(/^oklch\(/);
        });
    });

    describe("computeRelativeColor", () => {
        it("should produce a lighter color with positive offset", () => {
            const base = parseOklch("#007bff")!;
            const result = computeRelativeColor(
                base.l,
                base.c,
                base.h,
                base.alpha,
                0.1,
            );
            const resultL = Number.parseFloat(
                result.match(/oklch\(([0-9.]+)/)?.[1] ?? "0",
            );
            expect(resultL).toBeGreaterThan(base.l);
        });

        it("should produce a darker color with negative offset", () => {
            const base = parseOklch("#007bff")!;
            const result = computeRelativeColor(
                base.l,
                base.c,
                base.h,
                base.alpha,
                -0.1,
            );
            const resultL = Number.parseFloat(
                result.match(/oklch\(([0-9.]+)/)?.[1] ?? "0",
            );
            expect(resultL).toBeLessThan(base.l);
        });

        it("should clamp lightness to 0", () => {
            const result = computeRelativeColor(0.1, 0.15, 240, 1, -0.5);
            const resultL = Number.parseFloat(
                result.match(/oklch\(([0-9.]+)/)?.[1] ?? "-1",
            );
            expect(resultL).toBe(0);
        });

        it("should clamp lightness to 1", () => {
            const result = computeRelativeColor(0.9, 0.15, 240, 1, 0.5);
            const resultL = Number.parseFloat(
                result.match(/oklch\(([0-9.]+)/)?.[1] ?? "-1",
            );
            expect(resultL).toBe(1);
        });
    });

    describe("formatOklch", () => {
        it("should format with consistent precision", () => {
            const result = formatOklch(0.93, 0.045, 240.93, 1);
            expect(result).toBe("oklch(0.93 0.045 240.93 / 1)");
        });

        it("should trim trailing zeros", () => {
            const result = formatOklch(0.5, 0.1, 240, 1);
            expect(result).toBe("oklch(0.5 0.1 240 / 1)");
        });
    });
});

