            const result = getVariable(container, "primary-color");

            expect(result).toEqual({
                type: "variable",
                id: "test-id",
                name: "primary-color",
                value: "#007bff",
            });
        });

        it("should return the correct variable when multiple exist", () => {
            const container: Container = {
                id: "test-id",
                variables: [
                    {
                        type: "variable",
                        id: "test-id",
                        name: "primary-color",
                        value: "#007bff",
