        });

        it("should work for compact headings with tighter spacing", () => {
            const s = styleframe();
            const { letterSpacingTighter } = useLetterSpacingDesignTokens(s);

            s.selector(".display-heading", ({ variable }) => {
                variable("letter-spacing", s.ref(letterSpacingTighter));
